const imp = $('Impersonate Request').first().json || {};
const auth = $('Platform Authentication').first().json || {};

const token =
  imp.data?.access_token ||
  imp.access_token ||
  auth.data?.access_token ||
  auth.access_token ||
  '';

return [{ json: { bearer_token: String(token).trim().replace(/^Bearer\s+/i, '') } }];

const app = $('GET Application').first().json.data;
const filesData = $('GET Files').first().json.data || [];
const aliasData = $('GET Aliases').first().json;
const startInput = $node["Start"].json;
const customizations = $('GET Email Customization').first().json.data || [];

const dealClientName = (app.client?.name || '').trim().toLowerCase();
const aliases = aliasData.aliases || [];
const primary = aliasData.primary || {};

let matchedAlias = null;
if (dealClientName) {
  matchedAlias = aliases.find(a =>
    (a.client?.name || '').trim().toLowerCase() === dealClientName
  );
}

const aliasEmail  = matchedAlias ? matchedAlias.email : primary.email;
const aliasType   = matchedAlias ? 'alias' : 'gmail_primary';
const aliasId      = matchedAlias ? matchedAlias.email_alias_id : null;
const aliasClient = matchedAlias ? matchedAlias.client.name : 'Primary';

const snapshot = filesData.find(f => f.file_type === 'business_report');
const snapshotFileId   = snapshot ? snapshot.id : null;
const snapshotFileName = snapshot ? snapshot.original_name : null;
const base              = ($vars.platform_api_base_url || 'https://api.example.com').replace(/\/+$/, '');
const snapshotUrl      = snapshot ? `${base}/api/int/files/${snapshot.id}/download` : null;

const biz    = app.business || {};
const owner  = app.personal_information || {};
const prequal = app.prequalification || {};

const businessName    = biz.business_legal_name || app.application_name || 'Your Business';
const firstName       = owner.first_name
  ? owner.first_name.charAt(0).toUpperCase() + owner.first_name.slice(1).toLowerCase()
  : 'there';

// PASSWORD LOGIC: NAICS -> EIN -> ZIP
const rawNaics = String(biz.naics_code || biz.naics || '').replace(/[^\d]/g, '').trim();
const bizPiis = biz.piis || [];
const ownerPiis = owner.piis || [];
const einEntry = bizPiis.find(p => p.key === 'EIN') || ownerPiis.find(p => p.key === 'EIN');
const rawEin = einEntry ? String(einEntry.value || '').replace(/[^\d]/g, '').trim() : '';
const rawZip   = String(biz.zip || biz.postal_code || owner.zip || '').replace(/[^\d]/g, '').trim();

const pdfPassword     = rawEin || rawNaics || rawZip || null;
let pdfPasswordType = null;
if (rawEin) pdfPasswordType = 'EIN';
else if (rawNaics) pdfPasswordType = 'NAICS Code';
else if (rawZip) pdfPasswordType = 'ZIP Code';

// Metrics for HTML
const monthlyRevenue  = biz.actual_monthly_revenue
  ? '$' + Number(biz.actual_monthly_revenue).toLocaleString('en-US', { maximumFractionDigits: 0 })
  : null;
const creditScore     = biz.actual_credit_score || owner.actual_credit_score || null;
const requestedAmount = prequal.requested_amount
  ? '$' + Number(prequal.requested_amount).toLocaleString('en-US')
  : null;

const metrics      = [requestedAmount, monthlyRevenue, creditScore ? 'Credit ' + creditScore : null].filter(Boolean);
const metricsLine = metrics.length > 0 ? metrics.join(' · ') : '';

// Missing stips
const missingStips = (app.stips || []).filter(s => !s.is_finished);
let stipsBlock = '';
if (missingStips.length > 0) {
  stipsBlock = '<p><strong>To keep things moving, we still need:</strong></p>'
    + '<p>' + missingStips.map(s => '• ' + s.name).join('<br/>') + '</p>'
    + '<p>If any of these are hard to track down, let me know — I can walk you through exactly what\'s needed.</p>';
}

// Password block (simple HTML only — no inline styles)
let passwordBlock = '';
if (snapshot && pdfPassword) {
  passwordBlock = `<p><strong>This document is password-protected.</strong><br/>To open it, enter your business <strong>${pdfPasswordType}</strong> when prompted.</p>`;
}

// Email body — English, no signature (Platform adds it automatically)
const emailHtml = `<p>${firstName},</p>
  <p>We have an update on the funding application for <strong>${businessName}</strong>.</p>
  ${metricsLine ? `<p><em>${metricsLine}</em></p>` : ''}
  <p>Please find the attached <strong>Secure Document Snapshot</strong> with a complete overview of your application, including lender approvals, credit summary, and next steps.</p>
  ${passwordBlock}
  ${stipsBlock}
  <p>We're here to help you move forward as quickly as possible. Don't hesitate to reach out with any questions.</p>`;

// Subject
const emailSubject = `${businessName} — Funding Application Update`;
const activeCustomization = customizations.find(c => c.active === 1);
const emailCustomizationId = activeCustomization ? String(activeCustomization.id) : null;

return [{
  json: {
    ...startInput,
    email_subject: startInput.email_subject || emailSubject,
    email_html: emailHtml,
    contact_email: startInput.contact_email || owner.email_address || '',
    preferred_email_value: aliasEmail || startInput.preferred_email_value,
    preferred_email_type: aliasType || startInput.preferred_email_type,
    snapshot_file_name: snapshotFileName,
    snapshot_download_url: snapshotUrl,
    has_snapshot: !!snapshot,
    pdf_password: pdfPassword,
    pdf_password_type: pdfPasswordType,
    business_name: businessName,
    email_customization_id: emailCustomizationId,
    app_data_id: app.id || startInput.application_id
  }
}];

const j     = $json;
const token = String($('Proper Bearer Token').first().json.bearer_token || '').trim();

const appId        = String(j.application_id        || '').trim();
const contactEmail = String(j.contact_email         || '').trim();
const subject      = String(j.email_subject         || '').trim();
const html         = String(j.email_html            || '');
const senderId     = String(j.sender_platform_user_id     || '').trim();
const prefValue    = String(j.preferred_email_value || '').trim();
const prefType     = String(j.preferred_email_type  || 'gmail_primary').trim();
const bcc          = String(j.bcc                   || '').trim();
const templateId   = String(j.email_template_id     || '').trim();
const hasSnapshot  = !!j.has_snapshot;
const appDataId    = String(j.app_data_id           || appId).trim();
const businessName = String(j.business_name         || appId).trim();
const advisorName  = String(j.advisor_name          || 'Funding Advisor').trim();
const pdfPassword  = j.pdf_password      || null;
const pdfPassType  = j.pdf_password_type || null;

const slackChannel  = String(j.slack_channel_id || '').trim();
const rawTs         = String(j.slack_thread_ts  || '').trim();
const slackThreadTs = /^\d+\.\d+$/.test(rawTs) ? rawTs : null;

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const missing    = [];

if (!appId)        missing.push('application_id');
if (!contactEmail) missing.push('contact_email');
else if (!emailRegex.test(contactEmail)) missing.push('contact_email (formato inválido: ' + contactEmail + ')');
if (!subject)      missing.push('email_subject');
if (!html)         missing.push('email_html');
if (!token)        missing.push('access_token (Auth/Impersonation falló)');
if (!prefValue)    missing.push('preferred_email_value (alias/from email)');
if (!senderId)     missing.push('sender_platform_user_id');

if (!hasSnapshot)  missing.push('_warn: sin Secure Document Snapshot — el email se enviará sin adjunto');
if (hasSnapshot && !pdfPassword) missing.push('_warn: snapshot encontrado pero sin EIN ni ZIP — PDF se enviará sin contraseña');

const base          = ($vars.platform_api_base_url || 'https://api.example.com').replace(/\/+$/, '');
const notesEndpoint = `${base}/api/int/notes`;

const hardMissing = missing.filter(m => !String(m).startsWith('_warn'));
const ok          = hardMissing.length === 0;

const noteComment = hasSnapshot
  ? `Secure Document Snapshot enviado a ${contactEmail}${pdfPassword ? ' (PDF protegido con ' + pdfPassType + ')' : ''}. Asunto: "${subject}". Enviado desde ${prefValue}. Ejecución n8n: ${$execution.id}.`
  : `Email enviado a ${contactEmail} sin adjunto. Asunto: "${subject}". Enviado desde ${prefValue}. Ejecución n8n: ${$execution.id}.`;

return [{
  json: {
    ...j,
    _clean_app_id:          appId,
    _clean_app_data_id:     appDataId,
    _clean_contact_email:   contactEmail,
    _clean_subject:         subject,
    _clean_html:            html,
    _clean_sender_id:       senderId,
    _clean_pref_value:      prefValue,
    _clean_pref_type:       prefType,
    _clean_bcc:             bcc,
    _clean_template_id:     templateId,
    _clean_customization_id: String(j.email_customization_id || '').trim(),
    _clean_slack_channel:   slackChannel,
    _clean_slack_thread_ts: slackThreadTs,
    _bearer_for_lf:         token,
    _notes_endpoint:        notesEndpoint,
    _has_snapshot:          hasSnapshot,
    _pdf_password:          pdfPassword,
    _pdf_password_type:     pdfPassType,
    _note_comment:          noteComment,
    _send_ready:            ok,
    _send_missing:          missing,
    _business_name:         businessName,
    _advisor_name:          advisorName
  }
}];

const prep     = $('Prepare Send Body').first().json;
const missing  = (prep._send_missing || []).filter(m => !String(m).startsWith('_warn'));
const warnings = (prep._send_missing || []).filter(m =>  String(m).startsWith('_warn'));

const dealUrl  = 'https://app.example.com/records/' + (prep._clean_app_id || prep.application_id || 'unknown');
const dealLink = '<' + dealUrl + '|' + (prep._clean_app_id || 'Unknown Deal') + '>';

const text = [
  ':rotating_light: *Send Aborted — Missing/Invalid Data*',
  '• Deal: '       + dealLink,
  '• Execution: `' + $execution.id + '`',
  '• Missing: `'   + missing.join(', ')  + '`',
  warnings.length  ? '• Warnings: `' + warnings.join(', ') + '`' : null
].filter(Boolean).join('\n');

return [{ json: {
  success:         false,
  outcome:         'send_validation_failed',
  application_id:  prep._clean_app_id || prep.application_id,
  missing,
  warnings,
  slack_ping_text: text
} }];

const items = $input.all();

for (const item of items) {
  if (item.binary && item.binary.snapshot_binary) {
    item.binary.snapshot_binary.mimeType = 'application/pdf';
    item.binary.snapshot_binary.fileExtension = 'pdf';
    item.binary.snapshot_binary.fileName = ($('Prepare Send Body').first().json.snapshot_file_name || 'Deal_Snapshot.pdf').replace(/\.bin$/, '.pdf');
  }
}

return items;
